// Parse config/properties → one item per location {propId,driveId,itemId,property}.
// If triggered by the webhook with a propId, sync only that one; schedule = all.
const doc = $input.first().json;
const fields = (doc.fields) || (doc.document && doc.document.fields) || {};
const arr = (fields.properties && fields.properties.arrayValue && fields.properties.arrayValue.values) || [];
let only = '';
try { only = ($('Webhook').first().json.body && $('Webhook').first().json.body.propId) || ''; } catch (e) {}
const out = [];
for (const it of arr) {
  const m = (it.mapValue && it.mapValue.fields) || {};
  const g = k => (m[k] && m[k].stringValue) || '';
  const propId = g('id'), driveId = g('driveId'), itemId = g('itemId');
  if (!propId || !driveId || !itemId) continue;
  if (only && propId !== only) continue;
  out.push({ json: { propId, driveId, itemId, property: g('property') } });
}
if (!out.length) throw new Error('Floorplan sync: no properties matched (check config/properties or the propId filter).');
return out;

// Choose the warehouse + office Site Plan tab names for this property, and the
// region/scale params, from the per-location profile (fallback = auto by name).
const item = $('Loop properties').item.json;
const resp = $input.first().json || {};
const ws = (resp.value || []).filter(w => w && w.name);
const names = ws.map(w => w.name);

const PROFILES = {
  'banana-fontana':    { tabs: ['WH Site Plan'], minCol: 14 },
  'terminal-west-sac': { tabs: ['Site Plan'], officeTabs: ['OFFICE SITEPLAN'] }
};
function pickProfile(propId) {
  if (PROFILES[propId]) return PROFILES[propId];
  const n = s => String(s).toLowerCase().replace(/[^a-z0-9]+/g, '');
  const np = n(propId);
  for (const k in PROFILES) { const nk = n(k); if (nk.length >= 6 && (np.includes(nk) || nk.includes(np))) return PROFILES[k]; }
  return {};
}
const prof = pickProfile(item.propId);
function matchOne(cands) {
  if (!cands) return '';
  for (const c of cands) {
    let hit = names.find(n => n.toLowerCase() === c.toLowerCase()); if (hit) return hit;
    hit = names.find(n => n.toLowerCase().includes(c.toLowerCase())); if (hit) return hit;
  }
  return '';
}
let whTab = matchOne(prof.tabs);
let ofTab = matchOne(prof.officeTabs);
if (!whTab) whTab = names.find(n => /site\s*plan|warehouse|\bwh\b|layout|floor/i.test(n) && !/office/i.test(n)) || '';
if (!ofTab) ofTab = names.find(n => /office/i.test(n) && /(site|plan|layout|floor|office)/i.test(n)) || '';
if (!whTab && ofTab) whTab = ofTab;
if (!whTab) whTab = names[0] || '';
if (!ofTab) ofTab = whTab;   // single-tab: office units come from the WH tab via type-split
return [{ json: {
  propId: item.propId, driveId: item.driveId, itemId: item.itemId,
  whTab, ofTab,
  minCol: prof.minCol != null ? prof.minCol : 0,
  maxCol: prof.maxCol != null ? prof.maxCol : 1000000,
  minRow: prof.minRow != null ? prof.minRow : 0,
  maxRow: prof.maxRow != null ? prof.maxRow : 1000000,
  colw: prof.colw || 0, rowh: prof.rowh || 0
} }];

// Shared parser → warehouse/office floors → Firestore typed PATCH for floorplans_auto/{propId}.
const meta = $('Pick tabs').item.json;
function vals(node) { try { const j = $(node).item.json; return Array.isArray(j.values) ? j.values : []; } catch (e) { return []; } }
const whValues = vals('Read WH plan');
const ofValues = vals('Read Office plan');
const region = { minCol: meta.minCol, maxCol: meta.maxCol, minRow: meta.minRow, maxRow: meta.maxRow };

function parseUnits(values, p) {
  p = p || {};
  const UNIT = /\b([A-Z]{1,3}\d{1,3}(?:-[A-Z0-9]{1,2})?)\b/g;
  const SF = /([\d,]+)\s*SF/i, DOCK = /Dock\s*#?\s*(\d+)/i;
  const NOISE = new Set(['M2', 'AC', 'CC', 'OHD']);
  const minCol = p.minCol != null ? p.minCol : 0, maxCol = p.maxCol != null ? p.maxCol : 1e9;
  const minRow = p.minRow != null ? p.minRow : 0, maxRow = p.maxRow != null ? p.maxRow : 1e9;
  const units = {};
  for (let r = 0; r < values.length; r++) {
    if (r < minRow || r > maxRow) continue;
    const row = values[r] || [];
    for (let c = 0; c < row.length; c++) {
      if (c < minCol || c > maxCol) continue;
      let cell = row[c]; if (cell === null || cell === undefined) continue;
      cell = String(cell).trim();
      if (!cell || cell === ' ' || cell === 'Â' || cell === ' ') continue;
      const dm = cell.match(DOCK);
      if (dm) { const id = 'DOCK' + String(dm[1]).padStart(2, '0'); if (!units[id]) units[id] = { col: c, row: r, sf: null, type: 'DOCK' }; continue; }
      UNIT.lastIndex = 0; let m;
      while ((m = UNIT.exec(cell))) {
        const id = m[1]; if (NOISE.has(id)) continue;
        let sf = null; const sm = cell.match(SF); if (sm) sf = parseInt(sm[1].replace(/,/g, ''), 10);
        const t = id.startsWith('DOCK') ? 'DOCK' : id[0] === 'R' ? 'OFFICE' : id[0] === 'P' ? 'PARKING' : 'WH';
        if (!units[id]) units[id] = { col: c, row: r, sf: sf, type: t };
      }
    }
  }
  return units;
}
function layoutFloor(units) {
  const targetW = meta.colw ? 0 : 960, targetH = meta.rowh ? 0 : 680;
  const ids = Object.keys(units);
  if (!ids.length) return { viewBox: '0 0 700 400', bg: null, items: [] };
  let minc = Infinity, minr = Infinity, maxc = -Infinity, maxr = -Infinity;
  for (const id of ids) { const d = units[id]; if (d.col < minc) minc = d.col; if (d.col > maxc) maxc = d.col; if (d.row < minr) minr = d.row; if (d.row > maxr) maxr = d.row; }
  const spanC = Math.max(1, maxc - minc), spanR = Math.max(1, maxr - minr);
  const COLW = meta.colw || Math.min(40, Math.max(8, 960 / spanC));
  const ROWH = meta.rowh || Math.min(40, Math.max(8, 680 / spanR));
  const items = [];
  for (const id of ids.sort()) {
    const d = units[id]; let w, h;
    if (d.type === 'DOCK') { w = 18; h = 18; } else if (d.type === 'PARKING') { w = 20; h = 14; }
    else { const sf = d.sf || 600; w = Math.round(Math.max(42, Math.min(130, Math.sqrt(sf) * 1.1))); h = 42; }
    items.push({ k: 'u', id, x: Math.round((d.col - minc) * COLW), y: Math.round((d.row - minr) * ROWH), w, h });
  }
  let maxx = 0, maxy = 0; for (const it of items) { if (it.x + it.w > maxx) maxx = it.x + it.w; if (it.y + it.h > maxy) maxy = it.y + it.h; }
  return { viewBox: '0 0 ' + (maxx + 40) + ' ' + (maxy + 40), bg: null, items };
}

const whAll = parseUnits(whValues, region), ofAll = parseUnits(ofValues, region);
const whFloor = {}, ofFloor = {};
for (const id in whAll) { (whAll[id].type === 'OFFICE' ? ofFloor : whFloor)[id] = whAll[id]; }
for (const id in ofAll) { if (ofAll[id].type === 'OFFICE') ofFloor[id] = ofAll[id]; }
const warehouse = layoutFloor(whFloor), office = layoutFloor(ofFloor);

function itemsArr(items) { return { arrayValue: { values: items.map(it => ({ mapValue: { fields: {
  k: { stringValue: it.k }, id: { stringValue: it.id },
  x: { integerValue: String(it.x) }, y: { integerValue: String(it.y) },
  w: { integerValue: String(it.w) }, h: { integerValue: String(it.h) } } } })) } }; }
function floorMap(f) { return { mapValue: { fields: { viewBox: { stringValue: f.viewBox }, bg: { nullValue: null }, items: itemsArr(f.items) } } }; }
const total = warehouse.items.length + office.items.length;
if (total === 0) throw new Error('Floorplan parse produced 0 units for ' + meta.propId + ' (tab "' + meta.whTab + '").');
const patchBody = { fields: {
  warehouse: floorMap(warehouse), office: floorMap(office),
  updatedAt: { stringValue: new Date().toISOString() },
  source: { stringValue: 'n8n floorplan sync' },
  wh_count: { integerValue: String(warehouse.items.length) },
  office_count: { integerValue: String(office.items.length) }
} };
return [{ json: { propId: meta.propId, patchBody, total } }];
